package com.cognizant.springlearn.controller; import java.util.*; import jakarta.validation.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import com.cognizant.springlearn.model.*; import com.cognizant.springlearn.service.*;
@RestController public class ApiController {final CountryService countries;final EmployeeService employees;ApiController(CountryService c,EmployeeService e){countries=c;employees=e;} @GetMapping("/hello")String hello(){return "Hello World!!";} @RequestMapping("/countries") List<Country> countries(){return countries.all();} @GetMapping("/countries/{code}")Country country(@PathVariable String code){return countries.get(code);}@PostMapping("/countries")ResponseEntity<Country> addCountry(@Valid @RequestBody Country c){return ResponseEntity.status(201).body(countries.add(c));}@PutMapping("/countries")Country updateCountry(@Valid @RequestBody Country c){return countries.update(c);}@DeleteMapping("/countries/{code}")ResponseEntity<Void> deleteCountry(@PathVariable String code){countries.delete(code);return ResponseEntity.noContent().build();}@GetMapping("/employees")List<Employee> employees(){return employees.all();}@PostMapping("/employees")ResponseEntity<Employee> addEmployee(@Valid @RequestBody Employee e){return ResponseEntity.status(201).body(employees.add(e));}@PutMapping("/employees")Employee updateEmployee(@Valid @RequestBody Employee e){return employees.update(e);}@DeleteMapping("/employees/{id}")ResponseEntity<Void> deleteEmployee(@PathVariable long id){employees.delete(id);return ResponseEntity.noContent().build();}@GetMapping("/departments")List<String> departments(){return List.of("HR","IT","Finance");}}
